import React, { useState, useEffect } from 'react';
import {
  CpuChipIcon,
  ChartBarIcon,
  ArrowTrendingUpIcon,
  MapIcon,
  LightBulbIcon,
  ExclamationTriangleIcon,
  MagnifyingGlassIcon,
  BeakerIcon,
  IdentificationIcon
} from '@heroicons/react/24/outline';

const GlassCard = ({ children, className = "" }) => (
  <div className={`backdrop-blur-md border border-white/20 shadow-xl rounded-[2rem] transition-all duration-500 ${className}`}>
    {children}
  </div>
);

const MLPredictionTab = () => {
  const [activeTab, setActiveTab] = useState('overview');
  const [predictions, setPredictions] = useState(null);
  const [recentAnalysis, setRecentAnalysis] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const token = localStorage.getItem('token');
      const headers = {
        'Authorization': `Bearer ${token}`
      };

      const [overviewRes, recentRes] = await Promise.all([
        fetch('http://localhost:5000/api/ml/prediction/overview', { headers }),
        fetch('http://localhost:5000/api/ml/prediction/recent', { headers })
      ]);

      const overview = await overviewRes.json();
      const recent = await recentRes.json();

      setPredictions(overview);
      setRecentAnalysis(recent.complaints || []);
    } catch (error) {
      console.error('Error fetching ML data:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-purple-600"></div>
      </div>
    );
  }

  const tabs = [
    { id: 'overview', name: 'Intelligence', icon: CpuChipIcon },
    { id: 'analysis', name: 'System Analysis', icon: BeakerIcon },
    { id: 'algorithms', name: 'Model Engine', icon: IdentificationIcon },
    { id: 'forecast', name: 'Forecasts', icon: ArrowTrendingUpIcon },
  ];

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Navigation Bar */}
      <GlassCard className="p-1 px-2 flex space-x-1 bg-gray-50/50">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`flex-1 flex items-center justify-center py-3 px-4 rounded-xl text-xs font-bold transition-all duration-300 ${activeTab === tab.id
              ? 'bg-white text-purple-600 shadow-sm'
              : 'text-gray-500 hover:text-gray-900 hover:bg-white/50'
              }`}
          >
            <tab.icon className={`h-4 w-4 mr-2 ${activeTab === tab.id ? 'text-purple-600' : 'text-gray-400'}`} />
            {tab.name}
          </button>
        ))}
      </GlassCard>

      {/* Tab Content Rendering */}
      <div className="min-h-[400px]">
        {activeTab === 'overview' && (
          <div className="space-y-8 animate-in slide-in-from-bottom-4 duration-700">
            {/* Quick Stats Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              {[
                { label: 'Total Node Complaints', value: predictions?.currentStats?.total, color: 'text-gray-900', icon: ChartBarIcon, bgColor: 'bg-blue-50' },
                { label: 'Active Processing', value: predictions?.currentStats?.active, color: 'text-orange-600', icon: CpuChipIcon, bgColor: 'bg-orange-50' },
                { label: 'System Resolutions', value: predictions?.currentStats?.resolved, color: 'text-green-600', icon: BeakerIcon, bgColor: 'bg-green-50' },
                { label: 'Efficiency Rate', value: `${predictions?.currentStats?.resolutionRate}%`, color: 'text-purple-600', icon: ArrowTrendingUpIcon, bgColor: 'bg-purple-50' }
              ].map((stat, i) => (
                <GlassCard key={i} className="p-5 flex items-center group hover:scale-[1.02] transition-transform">
                  <div className={`h-12 w-12 rounded-2xl ${stat.bgColor} flex items-center justify-center mr-4 group-hover:rotate-6 transition-transform`}>
                    <stat.icon className={`h-6 w-6 ${stat.color}`} />
                  </div>
                  <div>
                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{stat.label}</p>
                    <h4 className={`text-xl font-black ${stat.color} tabular-nums`}>{stat.value || 0}</h4>
                  </div>
                </GlassCard>
              ))}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <GlassCard className="p-8 lg:col-span-1">
                <div className="flex items-center justify-between mb-8">
                  <h3 className="text-xl font-bold text-gray-900">Risk Assessment</h3>
                  <ExclamationTriangleIcon className="h-6 w-6 text-orange-500" />
                </div>

                <div className="space-y-8">
                  <div className="relative pt-1">
                    <div className="flex items-center justify-between mb-2">
                      <span className="text-[10px] font-black text-purple-600 uppercase tracking-widest">Model Confidence</span>
                      <span className="text-sm font-black text-purple-600">{predictions?.predictions?.riskAssessment?.confidence || 75}%</span>
                    </div>
                    <div className="overflow-hidden h-2.5 mb-4 text-xs flex rounded-full bg-purple-100">
                      <div style={{ width: `${predictions?.predictions?.riskAssessment?.confidence || 75}%` }} className="shadow-none flex flex-col text-center whitespace-nowrap text-white justify-center bg-purple-600 transition-all duration-1000"></div>
                    </div>
                  </div>

                  <div className="p-6 bg-gray-50 rounded-3xl border border-gray-100 text-center">
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-2">Global Risk Factor</span>
                    <span className={`text-3xl font-black uppercase tracking-tighter ${predictions?.predictions?.riskAssessment?.overall === 'high' ? 'text-red-500' : 'text-green-600'}`}>
                      {predictions?.predictions?.riskAssessment?.overall || 'Stable'}
                    </span>
                  </div>
                </div>
              </GlassCard>

              <GlassCard className="p-8 lg:col-span-2 relative group overflow-hidden">
                <div className="absolute top-0 right-0 p-8">
                  <LightBulbIcon className="h-48 w-48 text-yellow-400/10 -mr-12 -mt-12 group-hover:scale-110 transition-transform duration-1000" />
                </div>
                <div className="relative">
                  <h3 className="text-xl font-bold text-gray-900 mb-6 tracking-tight">System Recommendations</h3>
                  <div className="space-y-4">
                    {predictions?.predictions?.recommendations?.map((rec, i) => (
                      <div key={i} className="flex items-start p-4 bg-white/50 border border-gray-100/50 rounded-2xl hover:border-purple-200 transition-all">
                        <div className="h-2 w-2 rounded-full bg-purple-500 mt-2 mr-4 shrink-0 shadow-[0_0_8px_rgba(168,85,247,0.4)]"></div>
                        <p className="text-sm font-bold text-gray-700 leading-tight">{rec}</p>
                      </div>
                    ))}
                  </div>
                </div>
              </GlassCard>
            </div>
          </div>
        )}

        {activeTab === 'analysis' && (
          <GlassCard className="p-8 bg-gray-900 text-white selection:bg-purple-500/30 animate-in slide-in-from-right-4 duration-700">
            <div className="flex items-center justify-between mb-10">
              <div>
                <h3 className="text-xl font-black tracking-tight">Deep Intelligence Log</h3>
                <p className="text-[10px] font-bold text-white/30 uppercase tracking-widest mt-1">Real-time Machine Learning Inferences</p>
              </div>
              <div className="h-10 w-10 rounded-2xl bg-white/5 flex items-center justify-center">
                <BeakerIcon className="h-6 w-6 text-purple-400" />
              </div>
            </div>

            <div className="space-y-3 max-h-[600px] overflow-y-auto pr-2 custom-scrollbar">
              {recentAnalysis.map((item, i) => (
                <div key={i} className="group flex flex-col p-6 bg-white/[0.02] border border-white/5 rounded-3xl hover:bg-white/[0.04] hover:border-white/10 transition-all cursor-default">
                  <div className="flex items-center mb-4">
                    <div className="h-10 w-10 bg-purple-600/10 rounded-xl flex items-center justify-center mr-4 border border-purple-500/20 group-hover:rotate-6 transition-transform">
                      <span className="text-[10px] font-black text-purple-400 font-mono">#{item.complaintId.slice(-2)}</span>
                    </div>
                    <div className="flex-1">
                      <div className="flex items-center justify-between">
                        <div className="text-sm font-black group-hover:text-purple-300 transition-colors uppercase tracking-tight">Citizen: {item.user?.name || 'Anonymous'}</div>
                        <div className="text-xs font-black text-green-400 tabular-nums">
                          {(item.mlPredictions?.category?.confidence || 0.85).toFixed(3)}
                        </div>
                      </div>
                      <div className="text-[9px] font-bold text-white/30 uppercase tabular-nums">Analysis Thread: {item.complaintId}</div>
                    </div>
                  </div>

                  <div className="pl-14">
                    <div className="p-4 bg-white/[0.03] border border-white/5 rounded-2xl mb-4 group-hover:border-purple-500/20 transition-colors">
                      <div className="text-[9px] font-black text-purple-400 uppercase tracking-widest mb-2 opacity-50">Citizen Payload Snippet</div>
                      <p className="text-xs text-white/70 italic leading-relaxed line-clamp-2">"{item.description}"</p>
                    </div>
                    <div className="flex items-center space-x-3">
                      <span className="text-[9px] font-black text-white px-2 py-0.5 rounded border border-white/10 uppercase tracking-widest bg-white/5">
                        Inference: {item.mlPredictions?.category?.predicted || item.category}
                      </span>
                      <span className="text-[9px] font-bold text-white/30 uppercase tracking-widest">
                        Neural Conf. Factor
                      </span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </GlassCard>
        )}

        {activeTab === 'algorithms' && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in slide-in-from-top-4 duration-700">
            {predictions?.algorithms?.map((algo, index) => (
              <GlassCard key={index} className="p-8 relative overflow-hidden group hover:scale-[1.02] transition-all">
                <div className="absolute -right-4 -bottom-4 h-24 w-24 bg-gray-100 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"></div>
                <div className="flex items-center justify-between mb-8">
                  <div className="p-4 bg-gray-900 rounded-3xl group-hover:rotate-12 transition-transform">
                    <CpuChipIcon className="h-6 w-6 text-white" />
                  </div>
                  <span className={`px-3 py-1 text-[10px] font-black uppercase rounded-xl tracking-widest ${algo.status === 'Active' ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'}`}>
                    {algo.status}
                  </span>
                </div>
                <h3 className="text-lg font-black text-gray-900 mb-2 leading-tight">{algo.name}</h3>
                <p className="text-xs text-gray-400 font-bold mb-8 leading-relaxed h-12 line-clamp-3">{algo.description}</p>
                <div className="flex justify-between items-end pt-6 border-t border-gray-100">
                  <div>
                    <span className="text-[9px] font-black text-gray-400 uppercase tracking-[0.2em] block mb-1">Reliability</span>
                    <span className="text-2xl font-black text-gray-900 tabular-nums">{algo.accuracy}</span>
                  </div>
                  <div className="text-[9px] font-black text-gray-400 uppercase underline cursor-pointer hover:text-purple-600">Model Details</div>
                </div>
              </GlassCard>
            ))}
          </div>
        )}

        {activeTab === 'forecast' && (
          <GlassCard className="p-10 animate-in fade-in zoom-in-95 duration-700 overflow-hidden relative">
            <div className="absolute top-0 right-0 p-10 opacity-10">
              <ArrowTrendingUpIcon className="h-64 w-64 text-purple-600" />
            </div>
            <div className="relative">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-12">
                <div>
                  <h3 className="text-2xl font-black text-gray-900 tracking-tight">Demand Volume Projections</h3>
                  <p className="text-sm font-bold text-gray-400 mt-1">Expected citizen reports for the next business cycle</p>
                </div>
                <div className="flex space-x-4">
                  <div className="px-4 py-2 bg-purple-50 rounded-2xl flex items-center">
                    <div className="h-2 w-2 rounded-full bg-purple-600 mr-2 shadow-[0_0_8px_rgba(147,51,234,0.5)]"></div>
                    <span className="text-[10px] font-black text-purple-600 uppercase tracking-widest text-[9px]">Predicted Volume</span>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-7 gap-6 h-80 items-end px-2">
                {predictions?.predictions?.weeklyForecast?.map((day, index) => {
                  const maxVal = 50;
                  const height = (day.predictedComplaints / maxVal) * 100;
                  return (
                    <div key={index} className="flex flex-col items-center group/bar relative">
                      <div className="absolute -top-12 opacity-0 group-hover/bar:opacity-100 transition-opacity bg-gray-900 text-white text-[10px] font-black px-3 py-1.5 rounded shadow-xl pointer-events-none z-10 whitespace-nowrap">
                        {day.predictedComplaints} Incidents Expected
                      </div>
                      <div className="w-full relative h-[250px] flex items-end justify-center">
                        <div
                          className="w-8 md:w-16 bg-gradient-to-t from-gray-900 via-gray-800 to-purple-600 rounded-2xl transition-all duration-700 shadow-xl group-hover/bar:brightness-125 group-hover/bar:scale-x-105"
                          style={{ height: `${Math.max(10, Math.min(100, height))}%` }}
                        >
                          <div className="absolute -top-7 left-1/2 -translate-x-1/2 text-sm font-black text-purple-600 tabular-nums">
                            {day.predictedComplaints}
                          </div>
                        </div>
                      </div>
                      <span className="mt-8 text-[11px] font-black text-gray-400 uppercase tracking-[0.2em]">
                        {new Date(day.date).toLocaleDateString('en', { weekday: 'short' })}
                      </span>
                    </div>
                  );
                })}
              </div>
            </div>
          </GlassCard>
        )}
      </div>
    </div>
  );
};

export default MLPredictionTab;
